const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const quoteLists = JSON.parse(localStorage.getItem('quote_lists') || '[]');
const quoteItems = JSON.parse(localStorage.getItem('quote_list_items') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Identify all qualifying 2-player basketball machines under $8,000 that are quotable
const qualifyingProducts = products.filter(p => {
  return p && p.category_code === 'basketball_sports_games' && p.players === 2 &&
    typeof p.price === 'number' && p.price <= 8000 && p.is_available_for_quote;
});

let cp1Passed = false;
let cp2Passed = false;
let cp3Passed = false;

if (qualifyingProducts.length >= 2 && Array.isArray(quoteRequests) && quoteRequests.length) {
  // Sort by price ascending to find the two cheapest qualifying machines
  const sorted = qualifyingProducts.slice().sort((a, b) => {
    if (a.price !== b.price) return a.price - b.price;
    const an = a.name || '';
    const bn = b.name || '';
    return an.localeCompare(bn);
  });
  const cheapestTwo = sorted.slice(0, 2);
  const cheapestIds = cheapestTwo.map(p => p.id);

  let bestRequest = null;
  let bestQuoteList = null;
  let bestCountCheapest = 0;
  let bestQualifyingIdsInList = [];

  for (const req of quoteRequests) {
    if (!req || !req.quote_list_id) continue;
    const listItems = quoteItems.filter(i => i.quote_list_id === req.quote_list_id);
    if (!listItems.length) continue;

    const productIdsInList = Array.from(new Set(listItems.map(i => i.product_id)));
    const countCheapest = cheapestIds.filter(id => productIdsInList.includes(id)).length;
    if (countCheapest > bestCountCheapest) {
      const ql = quoteLists.find(q => q.id === req.quote_list_id) || null;
      bestRequest = req;
      bestQuoteList = ql;

      // Within this list, find all items that match the same criteria (2P basketball under $8k)
      const qualifyingListItems = listItems.filter(it => {
        const p = products.find(pp => pp.id === it.product_id);
        return p && p.category_code === 'basketball_sports_games' && p.players === 2 &&
          typeof p.price === 'number' && p.price <= 8000 && p.is_available_for_quote;
      });
      bestQualifyingIdsInList = Array.from(new Set(qualifyingListItems.map(it => it.product_id)));
      bestCountCheapest = countCheapest;
    }
  }

  if (bestRequest && bestQuoteList) {
    // CP1 (0.40): Some submitted quote request's list includes BOTH of the two cheapest qualifying products
    cp1Passed = bestCountCheapest >= 2;

    // CP2 (0.30): For that same quote list, the only qualifying 2P basketball machines under $8k are exactly those two cheapest
    const onlyCheapestUsed = bestQualifyingIdsInList.every(id => cheapestIds.includes(id));
    const hasExactlyTwoQualifying = bestQualifyingIdsInList.length === 2 && bestCountCheapest === 2;
    cp2Passed = hasExactlyTwoQualifying && onlyCheapestUsed;

    // CP3 (0.30): That quote list has been submitted (status 'submitted') with contact details
    const hasContact = !!bestRequest.contact_name && !!bestRequest.email;
    cp3Passed = bestQuoteList.status === 'submitted' && hasContact;
  }
}

checkpoints.push({ passed: cp1Passed, weight: 0.4 });
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const projectItems = JSON.parse(localStorage.getItem('project_items') || '[]');

const requiredCategories = [
  'racing_driving',
  'ticket_redemption_games',
  'prize_cranes_merchandisers',
  'air_hockey_table_games'
];

let bestData = null; // { project, coverageCount, qualifyingCount }

for (const proj of projects) {
  if (!proj) continue;
  const items = projectItems.filter(i => i.project_id === proj.id && (Number(i.quantity) || 0) > 0);
  if (!items.length) continue;

  const qualifyingProductIds = [];
  const categorySet = new Set();

  for (const it of items) {
    const p = products.find(pp => pp.id === it.product_id);
    if (!p) continue;
    if (!p.is_available_for_project) continue;
    if (p.power_voltage !== 'v110') continue;
    if (typeof p.width_cm !== 'number' || p.width_cm > 130) continue;
    qualifyingProductIds.push(p.id);
    if (p.category_code) categorySet.add(p.category_code);
  }

  const uniqueQualifyingIds = Array.from(new Set(qualifyingProductIds));
  if (!uniqueQualifyingIds.length) continue;

  let coverageCount = 0;
  for (const code of requiredCategories) {
    if (categorySet.has(code)) coverageCount += 1;
  }

  if (!bestData ||
      coverageCount > bestData.coverageCount ||
      (coverageCount === bestData.coverageCount && uniqueQualifyingIds.length > bestData.qualifyingCount)) {
    bestData = {
      project: proj,
      coverageCount,
      qualifyingCount: uniqueQualifyingIds.length
    };
  }
}

let cp1Passed = false;
let cp2Passed = false;
let cp3Passed = false;

if (bestData) {
  const proj = bestData.project;
  const coverageCount = bestData.coverageCount;
  const qualifyingCount = bestData.qualifyingCount;

  // CP1 (0.50): Some project has at least one qualifying 110V ≤130 cm machine in EACH required category
  cp1Passed = coverageCount === requiredCategories.length;

  // CP2 (0.30): That same project has exactly 4 distinct qualifying machines (one per category)
  cp2Passed = cp1Passed && qualifyingCount === requiredCategories.length;

  // CP3 (0.20): That project has been saved (status 'saved') after assembling the qualifying lineup
  cp3Passed = cp1Passed && proj.status === 'saved';
}

checkpoints.push({ passed: cp1Passed, weight: 0.5 });
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
checkpoints.push({ passed: cp3Passed, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const manuals = JSON.parse(localStorage.getItem('manual_documents') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const searchParams = JSON.parse(localStorage.getItem('task3_manualSearchParams') || 'null');
let downloadedIds = JSON.parse(localStorage.getItem('task3_downloadedManualIds') || '[]');
if (!Array.isArray(downloadedIds)) downloadedIds = [];

const productById = {};
for (const p of products) {
  if (p && p.id) productById[p.id] = p;
}

// All qualifying manuals: installation manuals for prize cranes/merchandisers, active, year ≥ 2023
const qualifyingManuals = manuals.filter(m => {
  if (!m || m.is_active === false) return false;
  if (m.document_type !== 'installation_manual') return false;
  if (!m.published_at) return false;
  const d = new Date(m.published_at);
  if (isNaN(d.getTime()) || d.getFullYear() < 2023) return false;
  const prod = m.product_id ? productById[m.product_id] : null;
  if (!prod) return false;
  return prod.category_code === 'prize_cranes_merchandisers';
});

let newestManual = null;
if (qualifyingManuals.length) {
  const sorted = qualifyingManuals.slice().sort((a, b) => {
    const da = a.published_at ? new Date(a.published_at).getTime() : 0;
    const db = b.published_at ? new Date(b.published_at).getTime() : 0;
    return db - da;
  });
  newestManual = sorted[0];
}

// CP1 (0.30): User used the manuals search with documentType set to 'installation_manual'
const cp1Passed = !!(searchParams && searchParams.documentType === 'installation_manual');

// CP2 (0.30): User downloaded at least one qualifying installation manual (crane/merchandiser, year ≥ 2023)
const downloadedQualifying = qualifyingManuals.filter(m => downloadedIds.includes(m.id));
const cp2Passed = downloadedQualifying.length >= 1;

// CP3 (0.40): User downloaded specifically the newest qualifying installation manual
const cp3Passed = !!(newestManual && downloadedIds.includes(newestManual.id));

checkpoints.push({ passed: cp1Passed, weight: 0.3 });
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

