const serviceRequests = JSON.parse(localStorage.getItem('service_requests') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

const productById = {};
for (const p of products) {
  if (p && p.id) productById[p.id] = p;
}

let candidate = null;

for (const r of serviceRequests) {
  if (!r) continue;
  const prod = r.product_id ? productById[r.product_id] : null;
  const isAirHockeyProduct = prod && prod.category_code === 'air_hockey_table_games';
  const isAirHockeyCategory = r.product_category_code === 'air_hockey_table_games';
  const isOnSite = r.service_type === 'on_site_maintenance';

  if (isOnSite && (isAirHockeyCategory || isAirHockeyProduct)) {
    candidate = r;
    break;
  }
}

let cp1Passed = false;
let cp2Passed = false;
let cp3Passed = false;

if (candidate) {
  // CP1 (0.40): Request is for on-site maintenance on an air hockey/table games product
  cp1Passed = true;

  // CP2 (0.30): Preferred datetime is in June 2026 at 10:00 (local time string hour 10)
  const dtStr = candidate.preferred_datetime || '';
  let isJune2026 = false;
  let isTenAM = false;
  if (typeof dtStr === 'string' && dtStr.length >= 16) {
    if (dtStr.slice(0, 7) === '2026-06') {
      isJune2026 = true;
    }
    const m = dtStr.match(/T(\d{2}):(\d{2})/);
    if (m) {
      const hour = parseInt(m[1], 10);
      if (hour === 10) isTenAM = true;
    } else {
      // Fallback via Date if pattern not matched
      const d = new Date(dtStr);
      if (!isNaN(d.getTime()) && d.getFullYear() === 2026 && (d.getMonth() + 1) === 6 && d.getHours() === 10) {
        isJune2026 = true;
        isTenAM = true;
      }
    }
  }
  cp2Passed = isJune2026 && isTenAM;

  // CP3 (0.30): Issue description mentions a goal not detecting pucks / score not updating
  const desc = (candidate.issue_description || '').toLowerCase();
  const mentionsGoal = desc.indexOf('goal') !== -1;
  const mentionsScore = desc.indexOf('score') !== -1 || desc.indexOf('scoring') !== -1;
  const mentionsDetect = desc.indexOf('detect') !== -1 || desc.indexOf('sensor') !== -1;
  cp3Passed = mentionsGoal && (mentionsScore || mentionsDetect);
}

checkpoints.push({ passed: cp1Passed, weight: 0.4 });
