const checkpoints = [];

const distributors = JSON.parse(localStorage.getItem('distributors') || '[]');
const inquiries = JSON.parse(localStorage.getItem('distributor_inquiries') || '[]');

let candidate = null; // { inquiry, distributor }

for (const inq of inquiries) {
  if (!inq) continue;
  const dist = distributors.find(d => d && d.id === inq.distributor_id);
  if (!dist) continue;

  const isBerlinAuthorized = dist.region === 'europe' && dist.country === 'Germany' &&
    typeof dist.city === 'string' && dist.city.toLowerCase() === 'berlin' &&
    dist.is_authorized_distributor !== false;

  if (isBerlinAuthorized) {
    candidate = { inquiry: inq, distributor: dist };
    break;
  }
}

let cp1Passed = false;
let cp2Passed = false;
let cp3Passed = false;

if (candidate) {
  const inq = candidate.inquiry;
  const msg = (inq.message || '').toLowerCase();

  // CP1 (0.40): Inquiry is addressed to an authorized distributor in Berlin, Germany (Europe region)
  cp1Passed = true;

  // CP2 (0.30): Inquiry subject is a product-related inquiry
  cp2Passed = inq.subject === 'product_inquiry';

  // CP3 (0.30): Message mentions claw machines AND pricing AND availability AND an arcade context
  const mentionsClaw = msg.indexOf('claw') !== -1;
  const mentionsPrice = msg.indexOf('price') !== -1 || msg.indexOf('pricing') !== -1;
  const mentionsAvailability = msg.indexOf('availability') !== -1 || msg.indexOf('available') !== -1;
  const mentionsArcade = msg.indexOf('arcade') !== -1;
  cp3Passed = mentionsClaw && mentionsPrice && mentionsAvailability && mentionsArcade;
}

checkpoints.push({ passed: cp1Passed, weight: 0.4 });
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const demos = JSON.parse(localStorage.getItem('demo_registrations') || '[]');

// Find earliest upcoming trade_show with on-site demos
const qualifyingEvents = events.filter(e => {
  return e && e.status === 'upcoming' && e.event_type === 'trade_show' && !!e.has_on_site_demos;
});

let cp1Passed = false;
let cp2Passed = false;

if (qualifyingEvents.length) {
  qualifyingEvents.sort((a, b) => {
    const da = a.start_date ? new Date(a.start_date).getTime() : 0;
    const db = b.start_date ? new Date(b.start_date).getTime() : 0;
    return da - db;
  });
  const earliestEvent = qualifyingEvents[0];
  const eventStart = earliestEvent.start_date ? new Date(earliestEvent.start_date) : null;
  const earliestDateStr = eventStart && !isNaN(eventStart.getTime())
    ? eventStart.toISOString().slice(0, 10)
    : null;

  if (earliestDateStr) {
    const candidateReg = demos.find(r => {
      if (!r) return false;
      if (r.event_id !== earliestEvent.id) return false;
      if (typeof r.selected_date !== 'string') return false;
      const datePart = r.selected_date.slice(0, 10);
      return datePart === earliestDateStr && r.time_slot === '14:00';
    });

    if (candidateReg) {
      // CP1 (0.60): Demo registration is for the earliest qualifying event, on its first day, at 14:00
      cp1Passed = true;
      // CP2 (0.40): Registration status is submitted
      cp2Passed = candidateReg.status === 'submitted';
    }
  }
}

checkpoints.push({ passed: cp1Passed, weight: 0.6 });
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('financing_plan_definitions') || '[]');
const inquiries = JSON.parse(localStorage.getItem('financing_inquiries') || '[]');

function calcMonthly(principal, termMonths, annualRate) {
  const P = Number(principal) || 0;
  const n = Number(termMonths) || 0;
  const r = (Number(annualRate) || 0) / 100 / 12;
  if (!P || !n) return 0;
  if (!r) return Math.round((P / n) * 100) / 100;
  const payment = (P * r) / (1 - Math.pow(1 + r, -n));
  return Math.round(payment * 100) / 100;
}

let candidate = null; // { inquiry, plan36, plan48, payment36, payment48 }

for (const inq of inquiries) {
  if (!inq) continue;
  const price = Number(inq.equipment_price) || 0;
  if (!(price > 0 && price <= 20000)) continue;
  if (inq.currency !== 'usd') continue;

  const selectedPlan = plans.find(p => p && p.id === inq.selected_plan_id);
  if (!selectedPlan || selectedPlan.term_months !== 48) continue;
  if (inq.selected_term_months !== 48) continue;

  const plan36 = plans.find(p => p && p.currency === inq.currency && p.term_months === 36);
  if (!plan36) continue;

  const payment48 = calcMonthly(price, 48, selectedPlan.interest_rate_annual_percent);
  const payment36 = calcMonthly(price, 36, plan36.interest_rate_annual_percent);

  if (payment48 < payment36) {
    candidate = { inquiry: inq, plan36, plan48: selectedPlan, payment36, payment48 };
    break;
  }
}

let cp1Passed = false;
let cp2Passed = false;

if (candidate) {
  const inq = candidate.inquiry;

  // CP1 (0.60): For equipment ≤ $20,000 USD, user selected a 48-month plan whose monthly payment is lower than the 36-month alternative
  cp1Passed = true;

  // CP2 (0.40): Stored estimated_monthly_payment matches the calculated 48-month payment within $1 tolerance
  const stored = Number(inq.estimated_monthly_payment) || 0;
  const diff = Math.abs(stored - candidate.payment48);
  cp2Passed = diff <= 1;
}

checkpoints.push({ passed: cp1Passed, weight: 0.6 });
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

let candidate = null;

for (const sub of subs) {
  if (!sub) continue;
  const segments = Array.isArray(sub.market_segments) ? sub.market_segments : [];
  const hasFEC = segments.includes('family_entertainment_centers');
  const hasBowling = segments.includes('bowling_centers');
  const exactlyTwo = segments.length === 2 && hasFEC && hasBowling;
  const isMonthly = sub.email_frequency === 'monthly';
  const consent = sub.accepted_privacy_policy === true;
  const isActive = sub.status === 'active';

  if (exactlyTwo && isMonthly && consent && isActive) {
    candidate = sub;
    break;
  }
}

let cp1Passed = false;
let cp2Passed = false;

if (candidate) {
  // CP1 (0.70): Subscription uses ONLY FEC and Bowling segments, monthly frequency, active, with privacy accepted
  cp1Passed = true;

  // CP2 (0.30): Subscriber provided a plausible name and email (non-empty name and email containing '@')
  const nameOk = typeof candidate.full_name === 'string' && candidate.full_name.trim().length > 0;
  const emailOk = typeof candidate.email === 'string' && candidate.email.indexOf('@') !== -1;
  cp2Passed = nameOk && emailOk;
}

checkpoints.push({ passed: cp1Passed, weight: 0.7 });
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
